js_content:
let gauge;
let currentZoneIndex = -1;

function initGauge() {
  gauge = new Gauge(document.getElementById('gauge')).setOptions({
    pointer: { length: 0.6, strokeWidth: 0.035, color: '#000' },
    limitMax: true, limitMin: true,
    staticZones: [
      { strokeStyle: 'rgba(0,200,0,1)', min: 0, max: 60 },
      { strokeStyle: 'rgba(255,180,0,1)', min: 60, max: 80 },
      { strokeStyle: 'rgba(220,0,0,1)', min: 80, max: 100 }
    ]
  });
  gauge.animationSpeed = 11;
  gauge.setMinValue(WebCC.Properties.MinValue);
  gauge.maxValue = WebCC.Properties.MaxValue;
  gauge.set(WebCC.Properties.GaugeValue);
  document.getElementById('unit-label').textContent = WebCC.Properties.UnitLabel;
}

function setProperty(data) {
  switch (data.key) {
    case 'GaugeValue': gauge.set(data.value); break;
    case 'MinValue':   gauge.setMinValue(data.value); break;
    case 'MaxValue':   gauge.maxValue = data.value; break;
    case 'UnitLabel':  document.getElementById('unit-label').textContent = data.value; break;
  }
}

WebCC.start(
  function(result) {
    if (result) {
      initGauge();
      WebCC.onPropertyChanged.subscribe(setProperty);
    } else {
      console.error('[CWC] WinCC connection failed.');
    }
  },
  {
    methods: {
      BlinkZone: function(zoneIndex) { /* blink logic here */ },
      ResetDisplay: function() { gauge.set(WebCC.Properties.MinValue); }
    },
    events: ['ZoneChanged', 'OnAlarmTriggered'],
    properties: {
      GaugeValue: 20,
      MinValue: 0,
      MaxValue: 100,
      PumpStatus: false,
      UnitLabel: '%'
    }
  },
  [],
  10000
);

